// ─────────────────────────────────────────────────────────────
// ALGORITHM — ported from original
// ─────────────────────────────────────────────────────────────
function perfScore(fin, st, led, totLaps, stagePts) {
  const f = fin <= 5 ? 100-(fin-1)*2 : 100-((fin-1)/35)*100;
  const g = Math.min(100, Math.max(0, 50+(st-fin)*2.5));
  const l = totLaps > 0 ? (led/totLaps)*100 : 0;
  const s = (stagePts/20)*100;
  return Math.round(f*0.45 + s*0.15 + g*0.15 + l*0.15 + 100*0.1);
}

function getTier(r) {
  if (r >= 85) return { bg:"rgba(255,193,7,0.08)",  border:T.gold };
  if (r >= 75) return { bg:"rgba(30,144,255,0.08)", border:T.accent };
  if (r >= 68) return { bg:"rgba(106,155,191,0.06)",border:T.textMid };
  if (r >= 63) return { bg:"rgba(30,60,90,0.06)",   border:"#4a7a9b" };
  return         { bg:"rgba(20,40,60,0.04)",         border:"#3d6a85" };
}

function processRace(driversIn, raceName, trackType, totalLaps, results, prevRanksIn, recentFinishesIn) {
  const drivers = JSON.parse(JSON.stringify(driversIn));
  const recentFinishes = JSON.parse(JSON.stringify(recentFinishesIn));

  const prevRanks = {};
  TRACK_KEYS.forEach(key => {
    const sorted = [...drivers].sort((a,b) => b[key]-a[key]);
    sorted.forEach((d,i) => {
      if (!prevRanks[d.num]) prevRanks[d.num] = {};
      prevRanks[d.num][key] = i+1;
    });
  });

  const preSnap = {};
  drivers.forEach(d => { preSnap[d.num] = { overall:d.overall, superspeedway:d.superspeedway, intermediate:d.intermediate, short:d.short, road:d.road }; });

  const seasonStatsOut = {};
  const topFinishers = [];

  results.forEach(r => {
    const d = drivers.find(x => x.num === r.num);
    if (!d) return;
    const { fin, st, led, sp } = r;
    const ps = perfScore(fin, st, led, totalLaps, sp);

    if (!recentFinishes[d.num]) recentFinishes[d.num] = [];
    recentFinishes[d.num].unshift(fin);
    if (recentFinishes[d.num].length > 3) recentFinishes[d.num].pop();

    const recent = recentFinishes[d.num];
    const recentTop5s  = recent.filter(f => f <= 5).length;
    const recentTop10s = recent.filter(f => f <= 10).length;
    const momentum = recentTop5s >= 3 ? 1.5 : recentTop5s >= 2 ? 1.25 : recentTop10s >= 2 ? 1.1 : 1.0;

    const oldTrack = d[trackType];
    const goingUp = ps > oldTrack;
    const decay = goingUp ? 0.70 : 0.88;
    const rawNew = oldTrack * decay + ps * (1 - decay);
    const change = rawNew - oldTrack;
    const boosted = goingUp ? oldTrack + change * momentum : rawNew;
    const winBonus = fin === 1 ? 5 : fin <= 3 ? 3 : fin <= 5 ? 1 : 0;
    const penalty = fin >= 36 ? -2 : fin >= 32 ? -1 : 0;

    d[trackType] = Math.max(30, Math.min(99, Math.round(boosted + winBonus + penalty)));

    const trackBlend = Math.round(
      d.superspeedway*0.15 + d.intermediate*0.25 + d.short*0.20 + d.road*0.15 + d[trackType]*0.25
    );
    const avgRecent = recent.reduce((a,b) => a+b, 0) / recent.length;
    const recentScore = Math.round(100 - ((avgRecent-1)/35)*50);
    d.overall = Math.max(30, Math.min(99, Math.round(trackBlend*0.60 + recentScore*0.40)));

    seasonStatsOut[d.num] = { fin, st, led, sp };
    if (fin <= 5) topFinishers.push(`P${fin}: #${d.num} ${d.name}`);
  });

  const postSnap = {};
  drivers.forEach(d => { postSnap[d.num] = { overall:d.overall, superspeedway:d.superspeedway, intermediate:d.intermediate, short:d.short, road:d.road }; });

  return { drivers, prevRanks, recentFinishes, preSnap, postSnap, topFinishers, seasonStatsOut };
}

// ─────────────────────────────────────────────────────────────
// PASTE PARSER — ported from original
// ─────────────────────────────────────────────────────────────
function normalize(name) {
  return name.toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z\s]/g, "").replace(/\s+/g, " ").trim();
}

function findDriver(drivers, name) {
  const norm = normalize(name);
  let m = drivers.find(d => normalize(d.name) === norm);
  if (m) return m;
  const lastName = norm.split(" ").pop();
  m = drivers.find(d => normalize(d.name).split(" ").pop() === lastName);
  if (m) return m;
  m = drivers.find(d => normalize(d.name).includes(norm) || norm.includes(normalize(d.name)));
  if (m) return m;
  m = drivers.find(d => {
    const dLast = normalize(d.name).split(" ").pop();
    return dLast.includes(lastName) || lastName.includes(dLast);
  });
  return m || null;
}

function classifyLine(line) {
  const t = line.trim();
  if (!t) return "empty";
  if (/^(finish|starting pos|final status|laps completed|laps led|best lap|points|stage points|stage 1|stage 2|car|#|pos|position|time behind|best time|best speed|laps)$/i.test(t)) return "header";
  if (/logo$/i.test(t)) return "logo";
  if (/^(Running|Out|Accident|DNF|Engine|Mechanical|Electrical|Suspension|Transmission|Overheating|Vibration|Brakes|Retired|Rear Gear|Oil Pressure|Handling|Rear End|Power Steering|Fuel Pump|Ignition)$/i.test(t)) return "status";
  if (/^\d+\.\d+$/.test(t)) return "decimal";
  if (/^-\d+\.\d+$/.test(t)) return "decimal";
  if (/^\d+$/.test(t)) return "number";
  if (/[a-zA-Z]/.test(t)) return "name";
  return "other";
}

function parsePaste(drivers, raceText, stage1Text, stage2Text) {
  const raceLines = raceText.split("\n");
  const classified = raceLines
    .map(l => ({ raw:l.trim(), type:classifyLine(l) }))
    .filter(c => c.type !== "empty" && c.type !== "header" && c.type !== "logo");

  const raceData = {};
  for (let i = 0; i < classified.length; i++) {
    if (classified[i].type !== "name") continue;
    const driverName = classified[i].raw;
    let finishPos = null;
    for (let b = i-1; b >= 0; b--) {
      if (classified[b].type === "number") {
        const n = parseInt(classified[b].raw);
        if (n >= 1 && n <= 45) { finishPos = n; break; }
      }
      if (classified[b].type === "name") break;
    }
    const forwardNums = [], forwardTypes = [];
    for (let f = i+1; f < classified.length; f++) {
      if (classified[f].type === "name") break;
      if (classified[f].type === "header") continue;
      forwardNums.push(classified[f].raw);
      forwardTypes.push(classified[f].type);
    }
    let startPos = finishPos, lapsLed = 0;
    let idx = 0;
    if (idx < forwardNums.length && forwardTypes[idx] === "number") { startPos = parseInt(forwardNums[idx]); idx++; }
    if (idx < forwardNums.length && forwardTypes[idx] === "status") idx++;
    if (idx < forwardNums.length && forwardTypes[idx] === "number") idx++;
    if (idx < forwardNums.length && forwardTypes[idx] === "number") { lapsLed = parseInt(forwardNums[idx]); idx++; }
    if (finishPos !== null) raceData[driverName] = { fin:finishPos, st:startPos||finishPos, led:lapsLed };
  }

  function parseStage(text) {
    if (!text) return {};
    const cls = text.split("\n")
      .map(l => ({ raw:l.trim(), type:classifyLine(l) }))
      .filter(c => c.type !== "empty" && c.type !== "header" && c.type !== "logo");
    const out = {};
    for (let i = 0; i < cls.length; i++) {
      if (cls[i].type !== "name") continue;
      for (let f = i+1; f < cls.length; f++) {
        if (cls[f].type === "name") break;
        if (cls[f].type === "number") {
          const pts = parseInt(cls[f].raw);
          if (pts >= 1 && pts <= 10) out[cls[i].raw] = pts;
          break;
        }
      }
    }
    return out;
  }

  const s1 = parseStage(stage1Text), s2 = parseStage(stage2Text);
  const stagePoints = {};
  for (const [n,p] of Object.entries(s1)) stagePoints[n] = (stagePoints[n]||0)+p;
  for (const [n,p] of Object.entries(s2)) stagePoints[n] = (stagePoints[n]||0)+p;

  const results = [], unmatched = [];
  for (const [parsedName, data] of Object.entries(raceData)) {
    const driver = findDriver(drivers, parsedName);
    if (driver) {
      let sp = 0;
      for (const [sName, pts] of Object.entries(stagePoints)) {
        if (findDriver(drivers, sName) === driver) { sp = Math.min(20, pts); break; }
      }
      results.push({ num:driver.num, fin:data.fin, st:data.st, led:data.led, sp });
    } else {
      unmatched.push(parsedName);
    }
  }
  results.sort((a,b) => a.fin-b.fin);
  return { results, unmatched };
}

// ─────────────────────────────────────────────────────────────
// PREDICTOR BATTLE — Scoring
// ─────────────────────────────────────────────────────────────
function scoreEntry(predDrivers, actualResults) {
  if (!actualResults?.length || !predDrivers?.length) return null;
  const preds = predDrivers.map((d) => d.trim().toLowerCase());
  const actual = actualResults.map((d) => d.trim().toLowerCase());
  const top3 = actual.slice(0, 3);
  const top5 = actual.slice(0, 5);
  const top10 = actual.slice(0, 10);
  const winCorrect = preds[0] === actual[0];
  const winInTop3 = top3.includes(preds[0]);
  const winInTop5 = top5.includes(preds[0]);
  const top3Overlap = preds.slice(0, 3).filter((d) => top3.includes(d)).length;
  const top5Overlap = preds.slice(0, 5).filter((d) => top5.includes(d)).length;
  const top10Overlap = preds.slice(0, 10).filter((d) => top10.includes(d)).length;
  const points =
    (winCorrect ? 20 : winInTop3 ? 10 : winInTop5 ? 5 : 0) +
    top3Overlap * 6 + top5Overlap * 3 + top10Overlap * 1;
  return { winCorrect, winInTop3, winInTop5, top3Overlap, top5Overlap, top10Overlap, points };
}

