function RankingsTab({ drivers, prevRanks }) {
  const [trackFilter, setTrackFilter] = useState("overall");
  const sorted = [...drivers].sort((a,b) => b[trackFilter]-a[trackFilter]);

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:16 }}>
      <div style={{ display:"flex", gap:6, flexWrap:"wrap" }}>
        {TRACK_KEYS.map(k => (
          <TrackTypePill key={k} type={k} active={trackFilter===k} onClick={()=>setTrackFilter(k)} />
        ))}
      </div>
      <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
        {sorted.map((d, i) => {
          const tier = getTier(d.overall);
          const rank = i+1;
          const prev = prevRanks[d.num]?.[trackFilter];
          const change = prev ? prev - rank : 0;
          return (
            <div key={d.num} style={{ background:tier.bg, border:`1px solid ${tier.border}`, borderLeft:`3px solid ${tier.border}`, borderRadius:10, padding:"14px 18px", transition:"all 0.15s" }}>
              <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                <div style={{ width:38, height:38, borderRadius:"50%", background:`${tier.border}22`, border:`1px solid ${tier.border}`, display:"flex", alignItems:"center", justifyContent:"center", fontWeight:900, fontSize:14, color:tier.border, fontFamily:"'Barlow Condensed',sans-serif", flexShrink:0 }}>{rank}</div>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ display:"flex", alignItems:"center", gap:8, flexWrap:"wrap" }}>
                    <span style={{ fontSize:15, fontWeight:700, color:T.text }}>#{d.num} {d.name}</span>
                    {d.rookie && <span style={{ fontSize:9, fontWeight:700, color:"#4ade80", background:"rgba(34,197,94,0.12)", border:"1px solid rgba(34,197,94,0.25)", borderRadius:4, padding:"1px 6px", letterSpacing:1 }}>ROOKIE</span>}
                    {change > 0 && <span style={{ fontSize:11, fontWeight:700, color:T.green }}>▲{change}</span>}
                    {change < 0 && <span style={{ fontSize:11, fontWeight:700, color:T.red }}>▼{Math.abs(change)}</span>}
                    {change === 0 && prev && <span style={{ fontSize:10, color:T.textDim }}>—</span>}
                  </div>
                  <div style={{ fontSize:12, color:T.textDim, marginTop:2 }}>{d.team} · {d.mfg}</div>
                  <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"3px 16px", marginTop:8 }}>
                    {TRACK_KEYS.map(k => (
                      <div key={k}>
                        <div style={{ fontSize:9, color:T.textDim, letterSpacing:1, textTransform:"uppercase", marginBottom:2 }}>{TL[k]}</div>
                        <RatingMiniBar value={d[k]} type={k} />
                      </div>
                    ))}
                  </div>
                </div>
                <div style={{ fontSize:32, fontWeight:900, color:TC[trackFilter], fontFamily:"'Barlow Condensed',sans-serif", flexShrink:0, letterSpacing:-1 }}>{d[trackFilter]}</div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────
// PREDICTOR ENGINES — Pure Stats & Enhanced Pure Stats
// Translated directly from pure_stats_predictor.py and
// nascar_enhanced_pure_stats.py
// ─────────────────────────────────────────────────────────────

// Track type classifier for predictor engines (matches Python)
const PRED_ROAD_COURSES = [
  'Circuit Of The Americas','Sonoma Raceway','Watkins Glen International Raceway',
  'Watkins Glen International','Road America','Chicago Street Course',
  'Indianapolis Motor Speedway','Autodromo Hermanos Rodriguez',
  'San Diego Road Course','Charlotte Motor Speedway Roval',
  'Naval Base Coronado Street Course',
];
const PRED_SHORT_TRACKS = ['Martinsville Speedway','Bristol Motor Speedway','Richmond Raceway','North Wilkesboro Speedway','Iowa Speedway','New Hampshire Motor Speedway'];
const PRED_SUPERSPEEDWAYS = ['Daytona International Speedway','Talladega Superspeedway','Echopark Speedway'];

function predGetTrackType(trackName) {
  const tl = (trackName||"").toLowerCase();
  if (PRED_ROAD_COURSES.some(r => tl.includes(r.toLowerCase()))) return 'road_course';
  if (PRED_SHORT_TRACKS.some(r => tl.includes(r.toLowerCase()))) return 'short_track';
  if (PRED_SUPERSPEEDWAYS.some(r => tl.includes(r.toLowerCase()))) return 'superspeedway';
  return 'intermediate';
}

// Map SCHEDULE track names to CSV track names for fuzzy matching
// Schedule → CSV track name aliases (where names differ)
const PRED_TRACK_ALIASES = {
  "dover motor speedway": "dover international speedway",
  "atlanta motor speedway": "echopark speedway",
};

function predMatchTrack(scheduleTrack, csvTrack) {
  const a = scheduleTrack.toLowerCase().replace(/[^a-z0-9 ]/g,"").trim();
  const b = csvTrack.toLowerCase().replace(/[^a-z0-9 ]/g,"").trim();
  // Check alias first
  const aliasA = PRED_TRACK_ALIASES[a] || a;
  const aliasB = PRED_TRACK_ALIASES[b] || b;
  const a2 = aliasA.replace(/[^a-z0-9]/g,"");
  const b2 = aliasB.replace(/[^a-z0-9]/g,"");
  return a2 === b2 || a2.includes(b2) || b2.includes(a2);
}

// CSV row indices: [0:driver, 1:track, 2:year, 3:finish, 4:start, 5:lapsLed, 6:running, 7:manufacturer, 8:lapsCompleted, 9:raceDate]

function predBuildDriverIndex(csvData) {
  const idx = {};
  for (const r of csvData) {
    const d = r[0];
    if (!d) continue;
    if (!idx[d]) idx[d] = [];
    idx[d].push(r);
  }
  return idx;
}

// ── Pure Stats Predictor (from pure_stats_predictor.py) ──
function runPureStatsPrediction(csvData, scheduleTrack, scheduleType) {
  const driverIdx = predBuildDriverIndex(csvData);
  const trackType = predGetTrackType(scheduleTrack);
  const predictions = [];

  for (const driverName of FULL_TIMER_NAMES) {
    const rows = driverIdx[driverName];
    if (!rows || rows.length === 0) continue;

    // Sort by date (index 9) to get recent races
    const sorted = [...rows].sort((a,b) => (a[9]||"").localeCompare(b[9]||""));

    // Recent form (last 5)
    const recent = sorted.slice(-5);
    const recentAvg = recent.reduce((s,r)=>s+r[3],0)/recent.length;

    // Track-specific
    const trackRows = rows.filter(r => predMatchTrack(scheduleTrack, r[1]));
    const trackAvg = trackRows.length > 0 ? trackRows.reduce((s,r)=>s+r[3],0)/trackRows.length : 20.0;
    const trackWins = trackRows.filter(r => r[3]===1).length;
    const trackRaces = trackRows.length;

    // Track-type performance
    const typeRows = rows.filter(r => predGetTrackType(r[1]) === trackType);
    const typeAvg = typeRows.length > 0 ? typeRows.reduce((s,r)=>s+r[3],0)/typeRows.length : 20.0;
    const typeWins = typeRows.filter(r => r[3]===1).length;
    const typeRaces = typeRows.length;

    // Calculate score (lower = better) — exact Python logic
    let score;
    if (trackRaces >= 3) {
      score = trackAvg*0.6 + typeAvg*0.3 + recentAvg*0.1;
    } else if (typeRaces >= 5) {
      score = typeAvg*0.7 + recentAvg*0.3;
    } else {
      score = typeAvg*0.5 + recentAvg*0.5;
    }

    // Win bonuses (exact Python logic)
    if (trackWins > 0) score *= 0.8;
    if (typeWins > 2) score *= 0.9;

    // Convert to probabilities (exact Python logic)
    const winProb  = Math.max(5, Math.min(95, 100 - score*2.5)) / 100;
    const top5Prob = Math.max(10, Math.min(95, 110 - score*2.0)) / 100;
    const top10Prob = Math.max(20, Math.min(95, 120 - score*1.5)) / 100;

    // Find driver info from INITIAL_DRIVERS for display
    const dInfo = INITIAL_DRIVERS.find(d => d.name === driverName);

    predictions.push({
      driver: driverName,
      num: dInfo?.num || "?",
      team: dInfo?.team || "",
      mfg: dInfo?.mfg || "",
      rookie: dInfo?.rookie || false,
      score,
      winPct: (winProb*100).toFixed(1),
      top5Pct: (top5Prob*100).toFixed(1),
      top10Pct: (top10Prob*100).toFixed(1),
      trackAvg: trackAvg.toFixed(1),
      trackWins,
      typeAvg: typeAvg.toFixed(1),
      typeWins,
      recentAvg: recentAvg.toFixed(1),
      bonuses: "",
    });
  }

  predictions.sort((a,b) => a.score - b.score);
  return predictions;
}

// ── Enhanced Pure Stats Predictor (from nascar_enhanced_pure_stats.py) ──
const ENH_MFR_STRONG_TRACKS = {
  'Chevrolet': ['Martinsville Speedway','Phoenix Raceway','Richmond Raceway'],
  'Ford': ['Daytona International Speedway','Talladega Superspeedway','Michigan International Speedway'],
  'Toyota': ['Bristol Motor Speedway','Darlington Raceway','Richmond Raceway'],
};
const ENH_PLAYOFF_TRACKS = [
  'Darlington Raceway','World Wide Technology Raceway','Bristol Motor Speedway','Kansas Speedway',
  'Las Vegas Motor Speedway','Charlotte Motor Speedway','Phoenix Raceway',
  'Talladega Superspeedway','Martinsville Speedway','Homestead-Miami Speedway',
];

function runEnhancedPureStatsPrediction(csvData, scheduleTrack, scheduleType) {
  const driverIdx = predBuildDriverIndex(csvData);
  const trackType = predGetTrackType(scheduleTrack);
  const predictions = [];

  for (const driverName of FULL_TIMER_NAMES) {
    const rows = driverIdx[driverName];
    if (!rows || rows.length === 0) continue;

    const sorted = [...rows].sort((a,b) => (a[9]||"").localeCompare(b[9]||""));

    // Recent 5 overall
    const recent = sorted.slice(-5);
    const recentAvg = recent.reduce((s,r)=>s+r[3],0)/recent.length;
    const recentWins = recent.filter(r=>r[3]===1).length;

    // Track-specific
    const trackRows = rows.filter(r => predMatchTrack(scheduleTrack, r[1]));
    const trackAvg = trackRows.length > 0 ? trackRows.reduce((s,r)=>s+r[3],0)/trackRows.length : 20.0;
    const trackWins = trackRows.filter(r=>r[3]===1).length;
    const trackRaces = trackRows.length;

    // Track-type
    const typeRows = rows.filter(r => predGetTrackType(r[1]) === trackType);
    const typeAvg = typeRows.length > 0 ? typeRows.reduce((s,r)=>s+r[3],0)/typeRows.length : 20.0;
    const typeWins = typeRows.filter(r=>r[3]===1).length;
    const typeRaces = typeRows.length;

    // Starting position
    const avgStartTrack = trackRows.length > 0 ? trackRows.reduce((s,r)=>s+r[4],0)/trackRows.length : 20.0;
    const avgStartType = typeRows.length > 0 ? typeRows.reduce((s,r)=>s+r[4],0)/typeRows.length : 20.0;

    // Recent at track type (last 3)
    const typeRowsSorted = [...typeRows].sort((a,b)=>(a[9]||"").localeCompare(b[9]||""));
    const recentType = typeRowsSorted.slice(-3);
    const recentTypeAvg = recentType.length > 0 ? recentType.reduce((s,r)=>s+r[3],0)/recentType.length : 20.0;

    // Trend: previous avg - last race (positive = improving)
    let recentTypeTrend = 0;
    if (recentType.length >= 2) {
      const lastRace = recentType[recentType.length-1][3];
      const prevAvg = recentType.slice(0,-1).reduce((s,r)=>s+r[3],0)/(recentType.length-1);
      recentTypeTrend = prevAvg - lastRace;
    }

    // Laps led dominance
    const trackLapsLed = trackRows.reduce((s,r)=>s+r[5],0);
    const trackLapsCompleted = trackRows.reduce((s,r)=>s+r[8],0);
    const trackLapsLedPct = trackLapsCompleted > 0 ? (trackLapsLed/trackLapsCompleted)*100 : 0;

    // Manufacturer
    const mfrCounts = {};
    rows.forEach(r => { const m = r[7]; if(m) mfrCounts[m] = (mfrCounts[m]||0)+1; });
    const manufacturer = Object.entries(mfrCounts).sort((a,b)=>b[1]-a[1])[0]?.[0] || "Unknown";

    // === BASELINE SCORE (exact Python weights) ===
    let trackWeight, typeWeight, recentWeight;
    if (trackRaces >= 5) {
      trackWeight=0.60; typeWeight=0.30; recentWeight=0.10;
    } else if (trackRaces >= 2) {
      trackWeight=0.40; typeWeight=0.40; recentWeight=0.20;
    } else {
      trackWeight=0.0; typeWeight=0.70; recentWeight=0.30;
    }
    const baseScore = trackAvg*trackWeight + typeAvg*typeWeight + recentAvg*recentWeight;

    // === ENHANCEMENTS (exact Python logic) ===
    const bonusTags = [];

    // E1: Manufacturer Track Bonus
    let mfrBonus = 0;
    if (ENH_MFR_STRONG_TRACKS[manufacturer]) {
      if (ENH_MFR_STRONG_TRACKS[manufacturer].some(t => predMatchTrack(scheduleTrack, t))) {
        mfrBonus = -0.5;
        bonusTags.push("Mfr");
      }
    }

    // E2: Starting Position Consistency
    let startBonus = 0;
    if (avgStartTrack < 10.0) { startBonus = -0.3; bonusTags.push("Qual"); }
    else if (avgStartType < 10.0) { startBonus = -0.2; bonusTags.push("Qual"); }

    // E3: Momentum
    let momBonus = 0;
    if (recentTypeTrend > 3.0) { momBonus = -0.4; bonusTags.push("Mom"); }
    else if (recentTypeTrend < -3.0) { momBonus = 0.3; bonusTags.push("Mom"); }

    // E4: Dominance (Laps Led)
    let domBonus = 0;
    if (trackLapsLedPct > 15.0) { domBonus = -0.6; bonusTags.push("Dom"); }
    else if (trackLapsLedPct > 5.0) { domBonus = -0.3; bonusTags.push("Dom"); }

    // E5: Win Multiplier
    let winMult = 1.0;
    if (trackWins >= 3) { winMult = 0.85; bonusTags.push("Win"); }
    else if (trackWins >= 1) { winMult = 0.92; bonusTags.push("Win"); }
    else if (typeWins >= 5) { winMult = 0.94; bonusTags.push("Win"); }

    // E6: Playoff Pressure
    let playoffBonus = 0;
    const isPlayoff = ENH_PLAYOFF_TRACKS.some(pt => predMatchTrack(scheduleTrack, pt));
    if (isPlayoff) {
      if (recentWins >= 1) { playoffBonus = -0.4; bonusTags.push("PO"); }
    }

    // Final enhanced score
    const enhancedScore = (baseScore + mfrBonus + startBonus + momBonus + domBonus + playoffBonus) * winMult;

    // Convert to probabilities (use same formula as Pure Stats for consistency)
    const winProb  = Math.max(5, Math.min(95, 100 - enhancedScore*2.5)) / 100;
    const top5Prob = Math.max(10, Math.min(95, 110 - enhancedScore*2.0)) / 100;
    const top10Prob = Math.max(20, Math.min(95, 120 - enhancedScore*1.5)) / 100;

    const dInfo = INITIAL_DRIVERS.find(d => d.name === driverName);

    predictions.push({
      driver: driverName,
      num: dInfo?.num || "?",
      team: dInfo?.team || "",
      mfg: dInfo?.mfg || "",
      rookie: dInfo?.rookie || false,
      score: enhancedScore,
      winPct: (winProb*100).toFixed(1),
      top5Pct: (top5Prob*100).toFixed(1),
      top10Pct: (top10Prob*100).toFixed(1),
      trackAvg: trackAvg.toFixed(1),
      trackWins,
      typeAvg: typeAvg.toFixed(1),
      typeWins,
      recentAvg: recentAvg.toFixed(1),
      bonuses: bonusTags.length > 0 ? bonusTags.join(", ") : "—",
    });
  }

  predictions.sort((a,b) => a.score - b.score);
  return predictions;
}

// Predictor model metadata
// ─────────────────────────────────────────────────────────────
// THIS WEEK'S RACE — Sidebar (desktop) / Banner (mobile)
// ─────────────────────────────────────────────────────────────
function ThisWeekPanel({ csvData, drivers, incrementTool, mode }) {
  const [expanded, setExpanded] = useState(false);
  const [quickResults, setQuickResults] = useState(null);
  const [loading, setLoading] = useState(false);

  const race = useMemo(() => getThisWeeksRace(), []);
  const trackType = race ? (CSV_TRACK_TYPES[race.track] || TL[race.type] || "Intermediate") : "";
  const typeColor = race ? (TC[race.type] || T.accent) : T.accent;

  // Recent winners at this track from CSV
  const recentWinners = useMemo(() => {
    if (!csvData.length || !race) return [];
    // Parse either ISO "YYYY-MM-DD" or US "M/D/YYYY" (Excel re-save artifact) into a sortable number.
    const parseRaceDate = (s, fallbackYear) => {
      if (!s) return (fallbackYear || 0) * 10000;
      if (s.includes("-")) {
        // ISO: "2025-09-28"
        return parseInt(s.replace(/-/g, ""), 10) || (fallbackYear || 0) * 10000;
      }
      if (s.includes("/")) {
        // US: "9/28/2025" -> 20250928
        const [m, d, y] = s.split("/").map(n => parseInt(n, 10));
        if (y && m && d) return y * 10000 + m * 100 + d;
      }
      return (fallbackYear || 0) * 10000;
    };
    const wins = [];
    for (const r of csvData) {
      if (r[3] === 1 && predMatchTrack(race.track, r[1])) {
        wins.push({
          driver: r[0],
          year: r[2] || 0,
          sortKey: parseRaceDate(r[9], r[2]),
        });
      }
    }
    wins.sort((a, b) => b.sortKey - a.sortKey);
    return wins.slice(0, 3);
  }, [csvData, race]);

  // Days until race
  const daysUntil = useMemo(() => {
    if (!race?.raceDate) return null;
    const now = new Date();
    const diff = Math.ceil((race.raceDate - now) / (1000 * 60 * 60 * 24));
    return Math.max(0, diff);
  }, [race]);

  const runQuickPredict = () => {
    if (!race || !csvData.length) return;
    setLoading(true);
    incrementTool?.("this_week_predict");
    setTimeout(() => {
      const preds = runEnhancedPureStatsPrediction(csvData, race.track, race.type);
      setQuickResults(preds.slice(0, 5));
      setLoading(false);
    }, 300);
  };

  if (!race) return null;

  const trackTypeFull = TL[race.type] || race.type;

  // ── Mobile banner mode ──
  if (mode === "banner") {
    return (
      <div style={{ background: T.surface, borderBottom: `1px solid ${T.border}` }}>
        {/* Collapsed row */}
        <button
          onClick={() => setExpanded(!expanded)}
          style={{
            width: "100%", display: "flex", alignItems: "center", justifyContent: "space-between",
            padding: "10px 16px", background: "transparent", border: "none", cursor: "pointer", gap: 10,
          }}
        >
          <div style={{ display: "flex", alignItems: "center", gap: 10, flex: 1, minWidth: 0 }}>
            <div style={{
              width: 6, height: 28, borderRadius: 3, background: typeColor, flexShrink: 0,
            }} />
            <div style={{ minWidth: 0 }}>
              <div style={{
                fontSize: 11, fontWeight: 800, color: T.text, fontFamily: "'Barlow Condensed',sans-serif",
                letterSpacing: 1.5, textTransform: "uppercase", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
              }}>
                {race.name}
              </div>
              <div style={{ fontSize: 10, color: T.textDim, fontFamily: "'IBM Plex Mono',monospace" }}>
                {race.date} · <span style={{ color: typeColor }}>{trackTypeFull}</span>
                {daysUntil != null && (
                  <span style={{ color: daysUntil === 0 ? T.gold : T.textDim }}> · {daysUntil === 0 ? "RACE DAY" : `${daysUntil}d away`}</span>
                )}
              </div>
            </div>
          </div>
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={T.textDim} strokeWidth="2.5" strokeLinecap="round" style={{ transform: expanded ? "rotate(180deg)" : "rotate(0deg)", transition: "transform 0.2s", flexShrink: 0 }}>
            <polyline points="6 9 12 15 18 9" />
          </svg>
        </button>

        {/* Expanded content */}
        {expanded && (
          <div style={{ padding: "0 16px 14px", display: "flex", flexDirection: "column", gap: 10 }}>
            <div style={{ display: "flex", gap: 16, flexWrap: "wrap", fontSize: 11, color: T.textMid, fontFamily: "'IBM Plex Mono',monospace" }}>
              <span>{race.track}</span>
              <span>{race.length} mi · {race.laps} laps</span>
            </div>

            {recentWinners.length > 0 && (
              <div>
                <div style={{ fontSize: 9, fontWeight: 700, color: T.textDim, fontFamily: "'Barlow Condensed',sans-serif", letterSpacing: 2, textTransform: "uppercase", marginBottom: 4 }}>RECENT WINNERS HERE</div>
                {recentWinners.map((w, i) => (
                  <div key={i} style={{ fontSize: 11, color: T.text, fontFamily: "'IBM Plex Mono',monospace", lineHeight: 1.6 }}>
                    <span style={{ color: T.gold }}>🏆</span> {w.driver} <span style={{ color: T.textDim }}>({w.year})</span>
                  </div>
                ))}
              </div>
            )}

            {!quickResults ? (
              <button onClick={runQuickPredict} disabled={loading || !csvData.length}
                style={{
                  padding: "8px 16px", borderRadius: 6, border: `1px solid ${typeColor}40`,
                  background: `${typeColor}15`, color: typeColor, fontSize: 11, fontWeight: 700,
                  fontFamily: "'Barlow Condensed',sans-serif", letterSpacing: 1, textTransform: "uppercase",
                  cursor: csvData.length ? "pointer" : "default", display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
                }}>
                {loading ? <><Ic.Spinner /> Running…</> : "⚡ Quick Predict"}
              </button>
            ) : (
              <div>
                <div style={{ fontSize: 9, fontWeight: 700, color: "#e879f9", fontFamily: "'Barlow Condensed',sans-serif", letterSpacing: 2, textTransform: "uppercase", marginBottom: 4 }}>TOP 5 — ENHANCED PURE STATS</div>
                {quickResults.map((p, i) => (
                  <div key={i} style={{ display: "flex", alignItems: "center", gap: 8, padding: "4px 0", borderBottom: i < 4 ? `1px solid ${T.border}` : "none" }}>
                    <span style={{ width: 20, height: 20, borderRadius: "50%", background: i < 3 ? `${typeColor}22` : `${T.border}44`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 10, fontWeight: 900, color: i < 3 ? typeColor : T.textDim, flexShrink: 0 }}>{i + 1}</span>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontSize: 12, fontWeight: 700, color: T.text, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>#{p.num} {p.driver}</div>
                    </div>
                    <span style={{ fontSize: 10, color: T.gold, fontWeight: 700, fontFamily: "'IBM Plex Mono',monospace" }}>{p.winPct}%</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
    );
  }

  // ── Desktop sidebar mode ──
  return (
    <aside style={{
      width: "100%", height: "100%",
      background: T.surface, borderLeft: `1px solid ${T.border}`,
      display: "flex", flexDirection: "column", alignItems: "center", overflow: "auto",
      fontFamily: "'Barlow',sans-serif",
    }}>
      <div style={{ width: "100%", maxWidth: 300 }}>
      {/* Header stripe */}
      <div style={{
        padding: "14px 16px 12px", borderBottom: `1px solid ${T.border}`,
        background: `linear-gradient(135deg, ${typeColor}10, transparent)`,
      }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
          <div style={{
            width: 4, height: 32, borderRadius: 2, background: typeColor,
          }} />
          <div>
            <div style={{
              fontSize: 9, fontWeight: 700, color: T.textDim, fontFamily: "'IBM Plex Mono',monospace",
              letterSpacing: 2, textTransform: "uppercase", marginBottom: 2,
            }}>
              THIS WEEK
            </div>
            <div style={{
              fontSize: 16, fontWeight: 900, color: T.text, fontFamily: "'Barlow Condensed',sans-serif",
              letterSpacing: 1.5, textTransform: "uppercase", lineHeight: 1.1,
            }}>
              {race.name}
            </div>
          </div>
        </div>

        <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
          <span style={{
            display: "inline-block", padding: "2px 8px", borderRadius: 4,
            background: `${typeColor}18`, border: `1px solid ${typeColor}30`,
            fontSize: 10, fontWeight: 700, color: typeColor,
            fontFamily: "'Barlow Condensed',sans-serif", letterSpacing: 1, textTransform: "uppercase",
          }}>
            {trackTypeFull}
          </span>
          <span style={{ fontSize: 11, color: T.textMid, fontFamily: "'IBM Plex Mono',monospace" }}>
            {race.date}
          </span>
          {daysUntil != null && (
            <span style={{
              fontSize: 10, fontWeight: 700,
              color: daysUntil === 0 ? T.gold : daysUntil <= 2 ? T.green : T.textDim,
              fontFamily: "'IBM Plex Mono',monospace",
            }}>
              {daysUntil === 0 ? "🏁 RACE DAY" : `${daysUntil}d`}
            </span>
          )}
        </div>
      </div>

      {/* Track info */}
      <div style={{ padding: "12px 16px", borderBottom: `1px solid ${T.border}` }}>
        <div style={{ fontSize: 9, fontWeight: 700, color: T.textDim, fontFamily: "'Barlow Condensed',sans-serif", letterSpacing: 2, textTransform: "uppercase", marginBottom: 6 }}>
          TRACK INFO
        </div>
        <div style={{ fontSize: 12, color: T.textMid, fontFamily: "'IBM Plex Mono',monospace", lineHeight: 1.8 }}>
          {race.track}
        </div>
        <div style={{ display: "flex", gap: 12, marginTop: 6 }}>
          {[
            { label: "LENGTH", value: `${race.length} mi` },
            { label: "LAPS", value: race.laps },
          ].map(s => (
            <div key={s.label}>
              <div style={{ fontSize: 8, color: T.textDim, fontFamily: "'IBM Plex Mono',monospace", letterSpacing: 1.5 }}>{s.label}</div>
              <div style={{ fontSize: 14, fontWeight: 800, color: T.text, fontFamily: "'Barlow Condensed',sans-serif" }}>{s.value}</div>
            </div>
          ))}
          {race.week > 0 && (
            <div>
              <div style={{ fontSize: 8, color: T.textDim, fontFamily: "'IBM Plex Mono',monospace", letterSpacing: 1.5 }}>WEEK</div>
              <div style={{ fontSize: 14, fontWeight: 800, color: typeColor, fontFamily: "'Barlow Condensed',sans-serif" }}>{race.week}</div>
            </div>
          )}
        </div>
      </div>

      {/* Recent winners at this track */}
      {recentWinners.length > 0 && (
        <div style={{ padding: "12px 16px", borderBottom: `1px solid ${T.border}` }}>
          <div style={{ fontSize: 9, fontWeight: 700, color: T.textDim, fontFamily: "'Barlow Condensed',sans-serif", letterSpacing: 2, textTransform: "uppercase", marginBottom: 8 }}>
            RECENT WINNERS HERE
          </div>
          {recentWinners.map((w, i) => (
            <div key={i} style={{
              display: "flex", alignItems: "center", gap: 8, padding: "5px 0",
              borderBottom: i < recentWinners.length - 1 ? `1px solid ${T.border}` : "none",
            }}>
              <span style={{ fontSize: 13 }}>🏆</span>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 12, fontWeight: 700, color: T.text }}>{w.driver}</div>
                <div style={{ fontSize: 10, color: T.textDim, fontFamily: "'IBM Plex Mono',monospace" }}>{w.year}</div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Quick Predict */}
      <div style={{ padding: "12px 16px", flex: 1 }}>
        {!quickResults ? (
          <button onClick={runQuickPredict} disabled={loading || !csvData.length}
            style={{
              width: "100%", padding: "10px 14px", borderRadius: 8,
              border: `1px solid ${typeColor}40`, background: `${typeColor}12`,
              color: typeColor, fontSize: 12, fontWeight: 800,
              fontFamily: "'Barlow Condensed',sans-serif", letterSpacing: 1.5, textTransform: "uppercase",
              cursor: csvData.length ? "pointer" : "default",
              display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
              transition: "all 0.15s",
            }}
            onMouseEnter={e => { if (csvData.length) { e.currentTarget.style.background = `${typeColor}25`; e.currentTarget.style.borderColor = `${typeColor}70`; }}}
            onMouseLeave={e => { e.currentTarget.style.background = `${typeColor}12`; e.currentTarget.style.borderColor = `${typeColor}40`; }}
          >
            {loading ? <><Ic.Spinner /> Running…</> : "⚡ Quick Predict"}
          </button>
        ) : (
          <div>
            <div style={{ fontSize: 9, fontWeight: 700, color: "#e879f9", fontFamily: "'Barlow Condensed',sans-serif", letterSpacing: 2, textTransform: "uppercase", marginBottom: 8 }}>
              🔬 TOP 5 — ENHANCED PURE STATS
            </div>
            {quickResults.map((p, i) => {
              const dInfo = INITIAL_DRIVERS.find(d => d.num === p.num);
              return (
                <div key={i} style={{
                  display: "flex", alignItems: "center", gap: 8,
                  padding: "7px 0",
                  borderBottom: i < 4 ? `1px solid ${T.border}` : "none",
                }}>
                  <span style={{
                    width: 24, height: 24, borderRadius: "50%",
                    background: i === 0 ? `${T.gold}22` : i < 3 ? `${typeColor}22` : `${T.border}44`,
                    display: "flex", alignItems: "center", justifyContent: "center",
                    fontSize: 11, fontWeight: 900,
                    color: i === 0 ? T.gold : i < 3 ? typeColor : T.textDim,
                    flexShrink: 0,
                  }}>
                    {i + 1}
                  </span>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{
                      fontSize: 12, fontWeight: 700, color: T.text,
                      whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
                    }}>
                      #{p.num} {p.driver}
                    </div>
                    <div style={{ fontSize: 9, color: T.textDim, fontFamily: "'IBM Plex Mono',monospace" }}>
                      {dInfo?.team?.split(" ").map(w => w[0]).join("") || p.mfg}
                    </div>
                  </div>
                  <div style={{ textAlign: "right", flexShrink: 0 }}>
                    <div style={{ fontSize: 11, fontWeight: 800, color: T.gold, fontFamily: "'IBM Plex Mono',monospace" }}>
                      {p.winPct}%
                    </div>
                    <div style={{ fontSize: 8, color: T.textDim, fontFamily: "'IBM Plex Mono',monospace" }}>WIN</div>
                  </div>
                </div>
              );
            })}
            <button onClick={() => setQuickResults(null)}
              style={{
                width: "100%", marginTop: 10, padding: "6px", borderRadius: 6,
                border: `1px solid ${T.border}`, background: "transparent",
                color: T.textDim, fontSize: 10, fontFamily: "'IBM Plex Mono',monospace",
                cursor: "pointer", letterSpacing: 1,
              }}>
              ↻ Re-run
            </button>
          </div>
        )}
        {!csvData.length && (
          <div style={{ marginTop: 8, fontSize: 10, color: T.textDim, fontFamily: "'IBM Plex Mono',monospace", textAlign: "center" }}>
            CSV data loading…
          </div>
        )}
      </div>
      </div>
    </aside>
  );
}

const PRED_MODELS = [
  { id:"power",    label:"Power Rankings",     color:"#10b981", desc:"Supabase-connected live ratings", icon:"⚡" },
  { id:"pure",     label:"Pure Stats",         color:"#f59e0b", desc:"Track-type weighted statistics, no ML", icon:"📊" },
  { id:"enhanced", label:"Enhanced Pure Stats", color:"#e879f9", desc:"+ Manufacturer, momentum, dominance, win multipliers", icon:"🔬" },
];

// ─────────────────────────────────────────────────────────────
// PREDICTOR TAB — with model selector
// ─────────────────────────────────────────────────────────────
function PredictorTab({ drivers, csvData, incrementTool }) {
  const [selectedWeek, setSelectedWeek] = useState("");
  const [selectedModel, setSelectedModel] = useState("power");
  const [results, setResults] = useState([]);

  const race = selectedWeek === "allstar" ? SCHEDULE.find(r => r.allStar) : SCHEDULE.find(r => !r.allStar && r.week === parseInt(selectedWeek));
  const model = PRED_MODELS.find(m => m.id === selectedModel);
  const needsCsv = selectedModel === "pure" || selectedModel === "enhanced";
  const hasCsv = csvData.length > 0;

  const runPrediction = () => {
    if (!race) return;
    incrementTool?.("race_predictor");

    if (selectedModel === "power") {
      // Original Power Rankings model — unchanged
      const preds = drivers.map(d => {
        const trackRating = d[race.type];
        const overallRating = d.overall;
        let relatedBonus = 0;
        if (race.type === "superspeedway") relatedBonus = d.intermediate*0.5 + d.road*0.2;
        else if (race.type === "intermediate") relatedBonus = d.short*0.4 + d.superspeedway*0.3;
        else if (race.type === "short") relatedBonus = d.intermediate*0.4 + d.road*0.3;
        else if (race.type === "road") relatedBonus = d.short*0.3 + d.intermediate*0.3;
        relatedBonus = relatedBonus / 0.7;
        const composite = trackRating*0.60 + overallRating*0.25 + relatedBonus*0.15;
        const maxSwing = 2 + (1 - composite/100)*4;
        const score = composite + (Math.random()-0.5)*maxSwing;
        const norm = composite/100;
        return {
          driver: d.name, num: d.num, team: d.team, mfg: d.mfg, rookie: d.rookie,
          score, trackRating,
          winPct: Math.min(30, Math.max(0.3, Math.pow(norm,4)*35)).toFixed(1),
          top5Pct: Math.min(60, Math.max(3, Math.pow(norm,2.5)*60)).toFixed(1),
          top10Pct: Math.min(82, Math.max(10, Math.pow(norm,1.8)*82)).toFixed(1),
          trackAvg: "", trackWins: "", typeAvg: "", typeWins: "", recentAvg: "", bonuses: "",
        };
      }).sort((a,b) => b.score-a.score);
      setResults(preds);

    } else if (selectedModel === "pure") {
      const preds = runPureStatsPrediction(csvData, race.track, race.type);
      setResults(preds);

    } else if (selectedModel === "enhanced") {
      const preds = runEnhancedPureStatsPrediction(csvData, race.track, race.type);
      setResults(preds);
    }
  };

  const col = race ? TC[race.type] : T.accent;

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:20 }}>
      {/* Model Selector */}
      <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
        {PRED_MODELS.map(m => {
          const active = m.id === selectedModel;
          return (
            <button key={m.id} onClick={() => { setSelectedModel(m.id); setResults([]); }}
              style={{
                flex:"1 1 160px", padding:"12px 16px", borderRadius:10, cursor:"pointer",
                background: active ? `${m.color}18` : T.surface,
                border: `2px solid ${active ? m.color : T.border}`,
                textAlign:"left", transition:"all 0.15s",
              }}>
              <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:4 }}>
                <span style={{ fontSize:16 }}>{m.icon}</span>
                <span style={{ fontSize:13, fontWeight:800, color: active ? m.color : T.textMid, fontFamily:"'Barlow Condensed',sans-serif", letterSpacing:1, textTransform:"uppercase" }}>{m.label}</span>
              </div>
              <div style={{ fontSize:10, color: active ? `${m.color}cc` : T.textDim, fontFamily:"'IBM Plex Mono',monospace", lineHeight:1.4 }}>{m.desc}</div>
            </button>
          );
        })}
      </div>

      {/* CSV status for Pure Stats / Enhanced models */}
      <InfoLegend title="Prediction Colors & Models">
        <div>
          <div style={{ fontWeight:700, color:T.text, marginBottom:6, fontFamily:"'Barlow Condensed',sans-serif", fontSize:13, letterSpacing:1 }}>DRIVER COLORS IN RESULTS</div>
          <div style={{ display:"flex", flexDirection:"column", gap:3, marginBottom:10 }}>
            {[
              { label:"Gold border / rank circle", color:T.gold, desc:"Top 3 predicted finish (podium contenders)" },
              { label:"Track-type color border", color:T.accent, desc:"Colored by the track type of the selected race (blue = intermediate, red = short, green = superspeedway, purple = road)" },
              { label:"Tier-based border", color:T.textMid, desc:"Remaining drivers colored by their overall Power Rankings tier" },
            ].map(t => (
              <div key={t.label} style={{ display:"flex", alignItems:"center", gap:8 }}>
                <span style={{ width:10, height:10, borderRadius:3, background:t.color, flexShrink:0 }} />
                <span><span style={{ fontWeight:700, color:t.color }}>{t.label}</span> — {t.desc}</span>
              </div>
            ))}
          </div>
          <div style={{ fontWeight:700, color:T.text, marginBottom:6, fontFamily:"'Barlow Condensed',sans-serif", fontSize:13, letterSpacing:1 }}>ENHANCED PURE STATS BONUS TAGS</div>
          <div style={{ display:"flex", flexWrap:"wrap", gap:6, marginBottom:8 }}>
            {[
              { tag:"Mfr", desc:"Manufacturer track affinity" },
              { tag:"Qual", desc:"Strong qualifying history" },
              { tag:"Mom", desc:"Momentum (trending up or down)" },
              { tag:"Dom", desc:"Laps-led dominance at track" },
              { tag:"Win", desc:"Win multiplier active" },
              { tag:"PO", desc:"Playoff pressure bonus" },
            ].map(b => (
              <span key={b.tag} style={{ fontSize:10, padding:"2px 7px", borderRadius:4, background:`${T.accent}15`, border:`1px solid ${T.accent}30`, color:T.accentText }}>
                <span style={{ fontWeight:700 }}>{b.tag}</span> = {b.desc}
              </span>
            ))}
          </div>
          <div style={{ fontSize:11, color:T.textDim, borderTop:`1px solid ${T.border}`, paddingTop:8 }}>
            Pure Stats and Enhanced Pure Stats models read from CSV race history. Power Rankings model uses live Supabase ratings. Lower composite scores = better predicted finish.
          </div>
        </div>
      </InfoLegend>
      {needsCsv && (
        <div style={{ display:"flex", alignItems:"center", gap:12, padding:"10px 14px", background:T.surface, border:`1px solid ${T.border}`, borderRadius:10 }}>
          <div style={{ flex:1 }}>
            <div style={{ fontSize:10, color:T.textDim, letterSpacing:1.5, textTransform:"uppercase", fontFamily:"'Barlow Condensed',sans-serif", marginBottom:2 }}>CSV Data Source</div>
            <div style={{ fontSize:12, color:hasCsv ? T.green : T.textDim, fontFamily:"'IBM Plex Mono',monospace" }}>
              {hasCsv ? `✓ ${csvData.length.toLocaleString()} records loaded` : "No data — CSV loads automatically from GitHub. Use Admin Panel to upload manually."}
            </div>
          </div>
        </div>
      )}

      {/* Race selector + generate button */}
      <div style={{ display:"flex", gap:12, flexWrap:"wrap", alignItems:"flex-end" }}>
        <div style={{ flex:"1 1 300px" }}>
          <label style={{ fontSize:10, color:T.textDim, display:"block", marginBottom:6, letterSpacing:1.5, textTransform:"uppercase", fontFamily:"'Barlow Condensed',sans-serif" }}>Select Race</label>
          <select value={selectedWeek} onChange={e=>{ setSelectedWeek(e.target.value); setResults([]); }}
            style={{ width:"100%", background:T.surface2, border:`1px solid ${T.border}`, color:T.text, borderRadius:8, padding:"9px 12px", fontSize:13, outline:"none" }}>
            <option value="">Choose a race...</option>
            {SCHEDULE.map(r => <option key={r.allStar ? "allstar" : r.week} value={r.allStar ? "allstar" : r.week}>{r.allStar ? "★" : `Week ${r.week}`} · {r.date} · {r.name}{r.allStar ? " (Non-Points)" : ""}</option>)}
          </select>
        </div>
        <button onClick={runPrediction} disabled={!race || (needsCsv && !hasCsv)} style={{ padding:"9px 24px", background:(race && (!needsCsv||hasCsv))?model.color:"#1a2d40", color:(race && (!needsCsv||hasCsv))?"#fff":T.textDim, border:"none", borderRadius:8, cursor:(race && (!needsCsv||hasCsv))?"pointer":"default", fontSize:13, fontWeight:700, fontFamily:"'Barlow Condensed',sans-serif", letterSpacing:1, textTransform:"uppercase", boxShadow:(race && (!needsCsv||hasCsv))?`0 4px 18px ${model.color}44`:"none" }}>
          Generate Prediction
        </button>
      </div>

      {/* Track info badge */}
      {race && (
        <div style={{ padding:"10px 16px", background:`${col}10`, border:`1px solid ${col}30`, borderRadius:8, fontSize:13, color:col, fontFamily:"'Barlow Condensed',sans-serif", fontWeight:600, letterSpacing:0.5 }}>
          {race.track} &nbsp;·&nbsp; <span style={{ textTransform:"uppercase" }}>{TL[race.type]}</span> &nbsp;·&nbsp; {race.length} mi &nbsp;·&nbsp; {race.laps} laps
        </div>
      )}

      {/* Results list */}
      {results.length > 0 && (
        <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
          <div style={{ fontSize:10, color:model.color, letterSpacing:2, textTransform:"uppercase", fontFamily:"'Barlow Condensed',sans-serif", fontWeight:700, marginBottom:4 }}>
            {model.icon} {model.label} MODEL — {results.length} drivers ranked
          </div>
          {results.map((p, i) => {
            const dInfo = INITIAL_DRIVERS.find(d => d.num === p.num);
            const ovr = dInfo?.overall || 60;
            const tier = getTier(ovr);
            const medal = i===0?"🏆":i===1?"🥈":i===2?"🥉":"";
            const isStatModel = selectedModel !== "power";
            return (
              <div key={p.num+"-"+i} style={{ background:tier.bg, border:`1px solid ${i<3?col:tier.border}`, borderLeft:`3px solid ${i<3?col:tier.border}`, borderRadius:10, padding:"12px 16px" }}>
                <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                  <div style={{ width:34, height:34, borderRadius:"50%", background:`${i<3?col:tier.border}22`, display:"flex", alignItems:"center", justifyContent:"center", fontWeight:900, fontSize:13, color:i<3?col:tier.border, flexShrink:0 }}>{i+1}</div>
                  <div style={{ flex:1 }}>
                    <div style={{ fontSize:14, fontWeight:700, color:T.text }}>{medal} #{p.num} {p.driver}{p.rookie&&<span style={{ fontSize:9, color:"#4ade80", marginLeft:6 }}>ROOKIE</span>}</div>
                    <div style={{ fontSize:11, color:T.textDim }}>{p.team} · {p.mfg}</div>
                    <div style={{ display:"flex", gap:14, marginTop:5, flexWrap:"wrap" }}>
                      {[
                        ["Win", p.winPct+"%", T.gold],
                        ["Top 5", p.top5Pct+"%", T.gold],
                        ["Top 10", p.top10Pct+"%", T.gold],
                      ].map(([l,v,c])=>(
                        <div key={l} style={{ fontSize:11 }}><span style={{ color:T.textDim }}>{l}: </span><span style={{ color:c, fontWeight:700 }}>{v}</span></div>
                      ))}
                      {isStatModel && p.trackAvg && (
                        <>
                          <div style={{ fontSize:11 }}><span style={{ color:T.textDim }}>Trk Avg: </span><span style={{ color:col, fontWeight:700 }}>{p.trackAvg}</span></div>
                          <div style={{ fontSize:11 }}><span style={{ color:T.textDim }}>Type Avg: </span><span style={{ color:T.accentText, fontWeight:700 }}>{p.typeAvg}</span></div>
                          <div style={{ fontSize:11 }}><span style={{ color:T.textDim }}>Recent: </span><span style={{ color:T.text, fontWeight:700 }}>{p.recentAvg}</span></div>
                        </>
                      )}
                      {!isStatModel && p.trackRating != null && (
                        <div style={{ fontSize:11 }}><span style={{ color:T.textDim }}>{race ? TL[race.type] : "Track"} Rtg: </span><span style={{ color:col, fontWeight:700 }}>{p.trackRating}</span></div>
                      )}
                    </div>
                    {isStatModel && p.bonuses && p.bonuses !== "—" && p.bonuses !== "" && (
                      <div style={{ marginTop:4, display:"flex", gap:4, flexWrap:"wrap" }}>
                        {p.bonuses.split(", ").map(b => (
                          <span key={b} style={{ fontSize:9, fontWeight:700, padding:"1px 6px", borderRadius:4, background:`${model.color}20`, color:model.color, fontFamily:"'IBM Plex Mono',monospace", letterSpacing:0.5 }}>{b}</span>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────
// COMPARE TAB
// ─────────────────────────────────────────────────────────────
function CompareTab({ drivers }) {
  const [selected, setSelected] = useState([]);
  const [search, setSearch] = useState("");
  const filtered = search ? drivers.filter(d => d.name.toLowerCase().includes(search.toLowerCase()) || d.num.includes(search)) : drivers;
  const toggle = (num) => {
    setSelected(prev => prev.includes(num) ? prev.filter(n=>n!==num) : prev.length < 5 ? [...prev,num] : prev);
  };
  const selDrivers = selected.map(n => drivers.find(d => d.num===n)).filter(Boolean);
  const radar = () => {
    if (selDrivers.length < 2) return null;
    const size=280, cx=140, cy=140, R=90;
    const cats = [{k:"superspeedway",l:"SUPER"},{k:"intermediate",l:"INTER"},{k:"short",l:"SHORT"},{k:"road",l:"ROAD"}];
    const step = (2*Math.PI)/cats.length, sa = -Math.PI/2;
    const pt = (a,r) => ({ x:cx+Math.cos(a)*r, y:cy+Math.sin(a)*r });
    let svg = `<svg viewBox="0 0 ${size} ${size}" style="width:100%;max-width:${size}px;display:block;margin:0 auto;">`;
    [25,50,75,100].forEach(v => {
      const rr=(v/100)*R, pts=cats.map((_,i)=>pt(sa+i*step,rr));
      svg+=`<polygon points="${pts.map(p=>`${p.x},${p.y}`).join(" ")}" fill="none" stroke="rgba(255,255,255,0.07)"/>`;
    });
    cats.forEach((c,i) => {
      const a=sa+i*step, ep=pt(a,R+24), lp=pt(a,R);
      svg+=`<line x1="${cx}" y1="${cy}" x2="${lp.x}" y2="${lp.y}" stroke="rgba(255,255,255,0.05)"/>`;
      svg+=`<text x="${ep.x}" y="${ep.y+3}" fill="${TC[c.k]}" font-size="9" font-family="sans-serif" font-weight="700" text-anchor="middle">${c.l}</text>`;
    });
    selDrivers.forEach((d,di) => {
      const col=CC[di%CC.length];
      const pts=cats.map((c,i)=>pt(sa+i*step,((d[c.k]||0)/100)*R));
      svg+=`<polygon points="${pts.map(p=>`${p.x},${p.y}`).join(" ")}" fill="${col}18" stroke="${col}" stroke-width="2"/>`;
      pts.forEach(p=>{svg+=`<circle cx="${p.x}" cy="${p.y}" r="3" fill="${col}"/>`;});
    });
    svg+="</svg>";
    return svg;
  };
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:16 }}>
      <div>
        <p style={{ fontSize:11, color:T.textDim, marginBottom:8, letterSpacing:1, textTransform:"uppercase", fontFamily:"'Barlow Condensed',sans-serif" }}>Select up to 5 drivers to compare</p>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search drivers..."
          style={{ width:"100%", background:T.surface2, border:`1px solid ${T.border}`, color:T.text, borderRadius:8, padding:"8px 12px", fontSize:13, outline:"none", marginBottom:10, fontFamily:"'Barlow',sans-serif" }} />
        <div style={{ display:"flex", flexWrap:"wrap", gap:6, maxHeight:160, overflowY:"auto", padding:"2px 0" }}>
          {filtered.map(d => {
            const idx = selected.indexOf(d.num);
            const sel = idx >= 0;
            const col = sel ? CC[idx%CC.length] : "";
            return (
              <div key={d.num} onClick={()=>toggle(d.num)} style={{ padding:"4px 10px", borderRadius:6, fontSize:12, fontWeight:700, fontFamily:"'Barlow Condensed',sans-serif", cursor:"pointer", border:`1px solid ${sel?col:T.border}`, background:sel?`${col}20`:T.surface2, color:sel?col:T.textMid, letterSpacing:0.5, transition:"all 0.12s" }}>
                #{d.num} {d.name.split(" ").pop()}
              </div>
            );
          })}
        </div>
      </div>
      {selDrivers.length < 2 ? (
        <div style={{ padding:"40px", textAlign:"center", color:T.textDim, fontSize:13, background:T.surface, border:`1px solid ${T.border}`, borderRadius:12 }}>Select at least 2 drivers to compare.</div>
      ) : (
        <>
          <div style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:12, padding:"20px 16px" }}>
            <div dangerouslySetInnerHTML={{ __html: radar() }} />
            <div style={{ display:"flex", flexWrap:"wrap", gap:12, justifyContent:"center", marginTop:12 }}>
              {selDrivers.map((d,i) => (
                <span key={d.num} style={{ fontSize:11, fontWeight:700, color:CC[i%CC.length], fontFamily:"'Barlow Condensed',sans-serif", display:"flex", alignItems:"center", gap:5 }}>
                  <span style={{ width:10, height:10, borderRadius:"50%", background:CC[i%CC.length], display:"inline-block" }} />
                  #{d.num} {d.name}
                </span>
              ))}
            </div>
          </div>
          <div style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:12, overflow:"hidden" }}>
            <table style={{ width:"100%", borderCollapse:"collapse" }}>
              <thead>
                <tr style={{ borderBottom:`1px solid ${T.border}` }}>
                  <th style={{ textAlign:"left", padding:"10px 14px", fontSize:10, color:T.textDim, fontFamily:"'Barlow Condensed',sans-serif", letterSpacing:1.5, textTransform:"uppercase" }}>Category</th>
                  {selDrivers.map((d,i) => <th key={d.num} style={{ padding:"10px 12px", fontSize:11, fontWeight:700, color:CC[i%CC.length], fontFamily:"'Barlow Condensed',sans-serif" }}>#{d.num}</th>)}
                </tr>
              </thead>
              <tbody>
                {TRACK_KEYS.map(k => {
                  const vals = selDrivers.map(d => d[k]);
                  const best = Math.max(...vals);
                  return (
                    <tr key={k} style={{ borderBottom:`1px solid ${T.border}` }}>
                      <td style={{ padding:"9px 14px", fontSize:12, color:TC[k], fontWeight:700, fontFamily:"'Barlow Condensed',sans-serif" }}>{TL[k]}</td>
                      {selDrivers.map((d,i) => (
                        <td key={d.num} style={{ padding:"9px 12px", textAlign:"center", fontSize:15, fontWeight:900, fontFamily:"'Barlow Condensed',sans-serif", color:d[k]===best?TC[k]:T.textDim, background:d[k]===best?`${TC[k]}10`:"transparent" }}>
                          {d[k]}
                        </td>
                      ))}
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────
// TRENDS TAB
// ─────────────────────────────────────────────────────────────
function TrendsTab({ drivers, ratingHistory }) {
  const [selected, setSelected] = useState([]);
  const [trendKey, setTrendKey] = useState("overall");
  const [search, setSearch] = useState("");
  const filtered = search ? drivers.filter(d => d.name.toLowerCase().includes(search.toLowerCase()) || d.num.includes(search)) : drivers;
  const toggle = (num) => {
    setSelected(prev => prev.includes(num) ? prev.filter(n=>n!==num) : prev.length < 6 ? [...prev,num] : prev);
  };
  const trendSvg = () => {
    if (selected.length === 0 || ratingHistory.length < 2) return null;
    const W=420, H=200, P={t:22,r:70,b:26,l:36};
    const cw=W-P.l-P.r, ch=H-P.t-P.b, n=ratingHistory.length;
    let vals=[];
    selected.forEach(num => ratingHistory.forEach(s => { if(s[num]) vals.push(s[num][trendKey]||0); }));
    if (!vals.length) return null;
    const mn=Math.max(0,Math.min(...vals)-5), mx=Math.min(100,Math.max(...vals)+5), rng=mx-mn||1;
    const xp=i=>P.l+(i/(n-1))*cw, yp=v=>P.t+ch-((v-mn)/rng)*ch;
    const st=rng>20?10:5;
    const grids=[];
    for(let v=Math.ceil(mn/st)*st;v<=mx;v+=st) grids.push(v);
    let svg=`<svg viewBox="0 0 ${W} ${H}" style="width:100%;max-width:${W}px;display:block;">`;
    grids.forEach(v=>{svg+=`<line x1="${P.l}" x2="${W-P.r}" y1="${yp(v)}" y2="${yp(v)}" stroke="rgba(255,255,255,0.05)"/><text x="${P.l-6}" y="${yp(v)+3}" fill="#5a8aab" font-size="9" text-anchor="end">${v}</text>`;});
    ratingHistory.forEach((_,i)=>{svg+=`<text x="${xp(i)}" y="${H-6}" fill="#5a8aab" font-size="8" text-anchor="middle">R${i+1}</text>`;});
    selected.forEach((num,di)=>{
      const col=CC[di%CC.length];
      const pts=ratingHistory.map((s,i)=>s[num]?{x:xp(i),y:yp(s[num][trendKey]||0)}:null).filter(Boolean);
      if(pts.length<2) return;
      const pathD=pts.map((p,i)=>`${i===0?"M":"L"}${p.x},${p.y}`).join(" ");
      const drv=drivers.find(x=>x.num===num);
      const last=pts[pts.length-1];
      svg+=`<path d="${pathD}" fill="none" stroke="${col}" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>`;
      pts.forEach(p=>{svg+=`<circle cx="${p.x}" cy="${p.y}" r="2.5" fill="${col}"/>`;});
      svg+=`<text x="${last.x+5}" y="${last.y+3}" fill="${col}" font-size="8" font-weight="700">#${num} ${drv?.name.split(" ").pop()||""}</text>`;
    });
    svg+="</svg>";
    return svg;
  };
  const svg = trendSvg();
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:16 }}>
      <div>
        <p style={{ fontSize:11, color:T.textDim, marginBottom:8, letterSpacing:1, textTransform:"uppercase", fontFamily:"'Barlow Condensed',sans-serif" }}>Select drivers to track (up to 6)</p>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search drivers..."
          style={{ width:"100%", background:T.surface2, border:`1px solid ${T.border}`, color:T.text, borderRadius:8, padding:"8px 12px", fontSize:13, outline:"none", marginBottom:10, fontFamily:"'Barlow',sans-serif" }} />
        <div style={{ display:"flex", flexWrap:"wrap", gap:6, maxHeight:130, overflowY:"auto", padding:"2px 0" }}>
          {filtered.map(d => {
            const idx = selected.indexOf(d.num);
            const sel = idx >= 0;
            const col = sel ? CC[idx%CC.length] : "";
            return (
              <div key={d.num} onClick={()=>toggle(d.num)} style={{ padding:"4px 10px", borderRadius:6, fontSize:12, fontWeight:700, fontFamily:"'Barlow Condensed',sans-serif", cursor:"pointer", border:`1px solid ${sel?col:T.border}`, background:sel?`${col}20`:T.surface2, color:sel?col:T.textMid, transition:"all 0.12s" }}>
                #{d.num} {d.name.split(" ").pop()}
              </div>
            );
          })}
        </div>
      </div>
      <div>
        <p style={{ fontSize:11, color:T.textDim, marginBottom:8, letterSpacing:1, textTransform:"uppercase", fontFamily:"'Barlow Condensed',sans-serif" }}>Rating to track</p>
        <div style={{ display:"flex", gap:6, flexWrap:"wrap" }}>
          {TRACK_KEYS.map(k => <TrackTypePill key={k} type={k} active={trendKey===k} onClick={()=>setTrendKey(k)} />)}
        </div>
      </div>
      {selected.length === 0 ? (
        <div style={{ padding:"40px", textAlign:"center", color:T.textDim, fontSize:13, background:T.surface, border:`1px solid ${T.border}`, borderRadius:12 }}>Select drivers above to see rating trends.</div>
      ) : ratingHistory.length < 2 ? (
        <div style={{ padding:"40px", textAlign:"center", color:T.textDim, fontSize:13, background:T.surface, border:`1px solid ${T.border}`, borderRadius:12 }}>Need at least 2 races recorded to show trends.</div>
      ) : !svg ? (
        <div style={{ padding:"40px", textAlign:"center", color:T.textDim, fontSize:13, background:T.surface, border:`1px solid ${T.border}`, borderRadius:12 }}>No data for selected drivers.</div>
      ) : (
        <div style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:12, padding:"20px 16px" }}>
          <p style={{ fontSize:10, color:T.textDim, marginBottom:12, letterSpacing:1.5, textTransform:"uppercase", fontFamily:"'Barlow Condensed',sans-serif" }}>{TL[trendKey]} Rating Over Time</p>
          <div dangerouslySetInnerHTML={{ __html: svg }} />
          <div style={{ display:"flex", flexWrap:"wrap", gap:12, justifyContent:"center", marginTop:12 }}>
            {selected.map((num,i) => {
              const d=drivers.find(x=>x.num===num);
              return <span key={num} style={{ fontSize:11, fontWeight:700, color:CC[i%CC.length], fontFamily:"'Barlow Condensed',sans-serif", display:"flex", alignItems:"center", gap:5 }}><span style={{ width:14, height:3, borderRadius:2, background:CC[i%CC.length], display:"inline-block" }} />#{num} {d?.name||""}</span>;
            })}
          </div>
        </div>
      )}
    </div>
  );
}

